@pytest.mark.asyncio

async def test_developer_message() -> None:
    """Chat request that includes a developer role message alongside user messages."""
    client = create_client(api_key="test-key", base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/developer_message")
    request = ChatCompletionRequest.from_json("{\"messages\":[{\"content\":\"You are a coding assistant. Always respond with concise code examples.\",\"role\":\"developer\"},{\"content\":\"How do I reverse a string in Python?\",\"role\":\"user\"}],\"model\":\"gpt-4\"}")

    result = await client.chat(request)
    assert len(result.choices) == 1  # noqa: S101
    assert _alef_e2e_text(result.choices[0].message.content).lower() == "s[::-1]".lower()  # noqa: S101
    assert _alef_e2e_text(result.choices[0].finish_reason).lower() == "stop".lower()  # noqa: S101


